#include <iostream>
#include <string>
#include <sstream>
#include <iomanip>

class Product {
private:
    int id;
    std::string name;
    double price;
public:
    Product(int id = 0, std::string name = "Unnamed", double price = 0.0) :
        id(id), name(name), price(price) {}

    int getId() const { return id; }
    std::string getName() const { return name; }
    double getPrice() const { return price; }
};

int main() {
    std::stringstream ss;
    ss << std::fixed << std::setprecision(1);

    Product p1;
    ss << "P1: " << p1.getId() << ", " << p1.getName() << ", " << p1.getPrice() << std::endl;

    Product p2(101, "Laptop");
    ss << "P2: " << p2.getId() << ", " << p2.getName() << ", " << p2.getPrice() << std::endl;

    Product p3(102, "Mouse", 25.50);
    ss << "P3: " << p3.getId() << ", " << p3.getName() << ", " << p3.getPrice() << std::endl;

    std::cout << ss.str();
    return 0;
}
